				assert.Equal(t, FailureModeLandOperatorAttention, result.Results[0].OutcomeReason)
				meta := bead.GetNeedsHumanMeta(*got)
				assert.Contains(t, meta.Reason, "land coordination operator attention")
			}
		})
	}
}

