		b.Acceptance = "1. TestWorkLoopOperatorPromotedOpenDoesNotDowngradeAgain\n2. TestWorkLoopOperatorOverridePreservesCommitmentText\n3. TestWorkLoopHardManualRequiredStillParks\n4. cd cli && go test ./internal/agent/... ./cmd/... -run \"TestWorkLoop(OperatorPromotedOpenDoesNotDowngradeAgain|OperatorOverridePreservesCommitmentText|HardManualRequiredStillParks)\" passes\n5. cd cli && go test -short ./internal/agent/... ./internal/bead/... ./cmd/... passes\n6. lefthook run pre-commit passes"
		b.Labels = []string{"phase:2", "area:agent", "area:bead-lifecycle", "area:tests", "kind:test", "prevention", "spec:FEAT-010"}
