// TestStopCondition_NoProgress_IgnoresIntakeRoutingReviewAndOperatorStates
// verifies that isValidImplementationAttempt and shouldSuppressNoProgress both
// return false (no no-progress budget consumed) for every non-implementation
// outcome class: intake block, decomposition, claim race, routing preflight,
// quota, transport, auth/tool setup, review error, needs_human, and operator-
// required states. These outcomes should not trigger the no-progress cooldown.
func TestStopCondition_NoProgress_IgnoresIntakeRoutingReviewAndOperatorStates(t *testing.T) {
	cases := []struct {
		name   string
		report ExecuteBeadReport
	}{
		{
			name: "intake_block",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "intake_block",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "decomposition",
			report: ExecuteBeadReport{
				Status:    ExecuteBeadStatusDeclinedNeedsDecomposition,
				BaseRev:   "abc123",
				ResultRev: "abc123",
			},
		},
		{
			name: "claim_race",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "claim_race",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},

			pf, ok := ClassifyProviderFailure(result.Error)
			require.True(t, ok, "failed final event %q must classify as a provider failure", result.Error)
			assert.Equal(t, tc.wantReason, pf.Reason)
			assert.Equal(t, tc.wantRetryable, pf.Retryable)

			// Retryable-vs-hard-pin semantics: an unpinned worker may fall back
			// when retryable; a pinned worker never widens (hard-pin exhausted).
			unpinned := DecideProviderFallback(pf, false)
			assert.Equal(t, tc.wantRetryable, unpinned.Continue,
				"unpinned fallback must mirror retryability")
			pinned := DecideProviderFallback(pf, true)
			assert.False(t, pinned.Continue, "pinned worker must never widen its pin")
			assert.Equal(t, FallbackStopHardPinExhausted, pinned.StopReason)
		})
	}
}

